// Static martial arts seed — Muay Thai, Krav Maga, BJJ.
// No API calls. Idempotent: checks (art, name) before each insert.

import { admin, banner, c } from './_lib.js'

async function existingKeySet(art) {
  const { data, error } = await admin
    .from('martial_arts_techniques')
    .select('name')
    .eq('art', art)
  if (error) throw error
  return new Set(data.map((r) => r.name.toLowerCase()))
}

async function insertFresh(rows, existing) {
  const fresh = rows.filter((r) => !existing.has(r.name.toLowerCase()))
  if (fresh.length === 0) return 0
  const { error } = await admin.from('martial_arts_techniques').insert(fresh)
  if (error) { console.error('  insert error:', error.message); throw error }
  fresh.forEach((r) => existing.add(r.name.toLowerCase()))
  return fresh.length
}

