  console.log(`  techniques: +${mt1}`)

  console.log(c.cyan('4B — Muay Thai combinations'))
  const mt2 = await insertFresh(MT_COMBOS, mtEx)
  console.log(`  combinations: +${mt2}`)
  console.log(c.green(`  ✓ Muay Thai: ${mt1 + mt2} new`))

  // Krav Maga
  console.log(c.cyan('\n4C — Krav Maga'))
  const kmEx = await existingKeySet('krav_maga')
  const km1 = await insertFresh(KRAV_TECHNIQUES, kmEx)
  const km2 = await insertFresh(KRAV_SCENARIOS, kmEx)
  console.log(c.green(`  ✓ Krav Maga: ${km1} techniques + ${km2} scenarios`))

  // BJJ
  console.log(c.cyan('\n4D — BJJ positions'))
  const bjjEx = await existingKeySet('bjj')
  const bjj1 = await insertFresh(BJJ_POSITIONS, bjjEx)
  console.log(`  positions: +${bjj1}`)

  console.log(c.cyan('4E — BJJ techniques'))
  const bjj2 = await insertFresh(BJJ_TECHNIQUES, bjjEx)
  console.log(`  techniques: +${bjj2}`)
